data class ProfileUiState(
    val isLoading: Boolean = false,
    val profile: Profile? = null,
    val error: String? = null
)

sealed interface ProfileEffect {
    data object NavigateBack : ProfileEffect
    data class ShowSnackbar(val message: String) : ProfileEffect
}

viewLifecycleOwner.lifecycleScope.launch {
    viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
        launch { viewModel.state.collect(::render) }
        launch { viewModel.effects.collect(::handleEffect) }
    }
}

class EditorViewModel : ViewModel() {
    private val _state = MutableStateFlow(EditorUiState())
    val state: StateFlow<EditorUiState> = _state.asStateFlow()

    private val _effects = MutableSharedFlow<EditorEffect>(extraBufferCapacity = 1)
    val effects: SharedFlow<EditorEffect> = _effects.asSharedFlow()

    fun save() = viewModelScope.launch {
        _state.update { it.copy(isSaving = true, error = null) }
        runCatching { repository.save(_state.value.form) }
            .onSuccess {
                _state.update { it.copy(isSaving = false, isSaved = true) }
                _effects.emit(EditorEffect.NavigateBack)
            }
            .onFailure { error ->
                _state.update { it.copy(isSaving = false, error = error.message) }
            }
    }
}

@Composable
fun EditorRoute(viewModel: EditorViewModel, onBack: () -> Unit) {
    val state by viewModel.state.collectAsStateWithLifecycle()
    LaunchedEffect(viewModel) {
        viewModel.effects.collect { effect ->
            when (effect) {
                EditorEffect.NavigateBack -> onBack()
                is EditorEffect.ShowSnackbar -> Unit
            }
        }
    }
    EditorScreen(state = state, onSave = viewModel::save)
}

data class ChatUiState(
    val messages: List<MessageUi> = emptyList(),
    val isLoading: Boolean = false,
    val connection: ConnectionState = ConnectionState.Disconnected,
    val pendingDialog: DialogModel? = null
)

sealed interface ChatEffect {
    data class ScrollToMessage(val id: String) : ChatEffect
    data class OpenAttachment(val url: String) : ChatEffect
}

data class UiState(
    val data: Data? = null,
    val pendingEffect: PendingEffect? = null
)

data class PendingEffect(val id: String, val effect: Effect)

fun acknowledge(id: String) {
    _state.update { state ->
        if (state.pendingEffect?.id == id) state.copy(pendingEffect = null) else state
    }
}

private var submitJob: Job? = null

fun submit() {
    if (submitJob?.isActive == true) return
    submitJob = viewModelScope.launch {
        dispatch(Action.SubmitStarted)
        val result = runCatching { repository.submit() }
        dispatch(result.fold(
            onSuccess = { Action.SubmitSucceeded },
            onFailure = { Action.SubmitFailed(it.message ?: "Unknown") }
        ))
    }
}

data class BadUiState(
    val navigateBack: Boolean = false
)
// Rotation có thể đọc lại true và điều hướng lần nữa.

@Test
fun navigation_is_not_replayed_after_ack() = runTest {
    val vm = createViewModel()
    vm.onSaveSuccess()
    val effect = vm.state.value.pendingEffect!!
    vm.acknowledge(effect.id)

    val recreated = createViewModel(savedState = vm.savedSnapshot())
    assertNull(recreated.state.value.pendingEffect)
}
